from agents import Agent, handoff

router_agent = Agent(
    name="Document Router",
    instructions="""Classify document type and handoff:
    - 'invoice' → invoice_agent
    - 'contract' → contract_agent
    Respond with exact agent name for handoff."""
)

@handoff
def route_to_agent(doc_type: str, agent_name: str):
    """Execute handoff to specified agent"""
    if agent_name == 'invoice_agent':
        return invoice_agent.run(input)
    return contract_agent.run(input)

