from vex import Guardrail, RegexValidator

handoff_guardrail = Guardrail(
    name="handoff_instruction_guardrail",
    validators=[
        RegexValidator(
            pattern=r"^(invoice_agent|contract_agent)$",
            error_msg="Invalid handoff target"
        )
    ]
)

@vex.guardrail(handoff_guardrail)
def safe_handoff(classification: str):
    target_agent = router_agent.run(classification)
    return target_agent

# Blocks loops and invalid targets
safe_target = safe_handoff("invoice")
